SELECT id, path, name, city FROM stores WHERE city='Innsbruck' OR name LIKE '%Wilten%' ORDER BY id;

SELECT 'makita' AS q, sku, path, brand, series, model FROM products WHERE brand='Makita' AND series LIKE '%Makita XGT DHP%' AND model='31S-Q68' AND json_extract(properties,'$.power_source')='corded' AND json_extract(properties,'$.bar_length')='25 cm' LIMIT 5;
SELECT 'wd40' AS q, sku, path, brand, series, model FROM products WHERE brand='WD-40' AND series LIKE '%WD-40 Specialist WD%' AND model='25F-5RJ' AND json_extract(properties,'$.cleaner_type')='polish' AND json_extract(properties,'$.volume')='500 ml' LIMIT 5;
SELECT 'fischer' AS q, sku, path, brand, series, model FROM products WHERE brand='Fischer' AND series LIKE '%Fischer SX DUO%' AND model='1R7-M6Z' AND json_extract(properties,'$.anchor_type')='concrete anchor' AND json_extract(properties,'$.diameter')='12 mm' LIMIT 5;
SELECT 'viega' AS q, sku, path, brand, series, model FROM products WHERE brand='Viega' AND series LIKE '%Viega Professional Sanpress%' AND model='1NX-HRW' AND json_extract(properties,'$.fitting_type')='thread adapter' AND json_extract(properties,'$.diameter')='20 mm' LIMIT 5;
SELECT 'pattex' AS q, sku, path, brand, series, model FROM products WHERE brand='Pattex' AND series LIKE '%Pattex Crystal PX%' AND model='XQS-RSC' AND json_extract(properties,'$.adhesive_type')='tile adhesive' AND json_extract(properties,'$.color_family')='White' LIMIT 5;
SELECT 'osram' AS q, sku, path, brand, series, model FROM products WHERE brand='Osram' AND series LIKE '%Osram Smart Classic%' AND model='3QH-B92' AND json_extract(properties,'$.wattage')='10 W' AND json_extract(properties,'$.luminous_flux')='2452 lm' AND json_extract(properties,'$.fitting')='GU10' LIMIT 5;
